import { motion } from 'framer-motion';
import { LANDING_STATS } from '../../constants/landingData';

export default function StatsStrip() {
  return (
    <section className="relative bg-gradient-to-r from-emerald-600 via-emerald-600 to-emerald-700 text-white">
      <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,')] opacity-60" />
      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-8">
          {LANDING_STATS.map((stat, i) => (
            <motion.div
              key={stat.label}
              initial={{ opacity: 0, y: 12 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: i * 0.08 }}
              className="text-center"
            >
              <p className="text-3xl sm:text-4xl font-bold tracking-tight">{stat.value}</p>
              <p className="text-sm text-emerald-100 mt-1">{stat.label}</p>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}
